#include <stdio.h>
#include <stdint.h>

uint64_t calculateXorSum(uint64_t r1, uint64_t r2, uint64_t c1, uint64_t c2) {
    uint64_t xorSum = 0;
    for (uint64_t i = r1; i <= r2; i++) {
        uint64_t rowXorSum = 0;
        for (uint64_t j = c1; j <= c2; j++) {
            uint64_t cellValue = (i ^ j);
            rowXorSum ^= cellValue;
        }
        xorSum ^= rowXorSum;
    }
    return xorSum;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        uint64_t r1, r2, c1, c2;
        scanf("%llu %llu %llu %llu", &r1, &r2, &c1, &c2);
        uint64_t xorSum = calculateXorSum(r1, r2, c1, c2);
        printf("%llu\n", xorSum);
    }
    return 0;
}

