import java.util.Scanner;

public class Main {
    public static long calculateXorSum(long r1, long r2, long c1, long c2) {
        long xorSum = 0;
        for (long i = r1; i <= r2; i++) {
            long rowXorSum = 0;
            for (long j = c1; j <= c2; j++) {
                long cellValue = (i ^ j);
                rowXorSum ^= cellValue;
            }
            xorSum ^= rowXorSum;
        }
        return xorSum;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            long r1 = scanner.nextLong();
            long r2 = scanner.nextLong();
            long c1 = scanner.nextLong();
            long c2 = scanner.nextLong();
            long xorSum = calculateXorSum(r1, r2, c1, c2);
            System.out.println(xorSum);
        }
    }
}

